import { describe, it, expect } from "vitest";
import { quote } from "./quote.js";

describe("MHPCO premium quoting", () => {
  it.todo("quotes a single sword for a new customer (base 100 + initial 10% + 5 fee = 115)");
  it.todo("quotes a single amulet (60 base + 10% + fee)");
  it.todo("quotes a single staff (80 base + 10% + fee)");
  it.todo("quotes a single potion (40 base + 10% + fee)");
  it.todo("quotes a single rune component (25 base + 10% + fee)");
  it.todo("quotes three alike components as a building block (60 base + 10% + fee)");
  it.todo("quotes four runes: one block of 3 + one single = 85 base + 10% + fee");
  it.todo("adds 50% surcharge for a cursed item");
  it.todo("adds 30% surcharge for highly enchanted items (enchantment >= 5)");
  it.todo("stacks cursed and highly enchanted surcharges multiplicatively");
  it.todo("applies 20% loyalty discount for customers with >= 2 years");
  it.todo("does not apply 10% initial surcharge after the first quote");
  it.todo("applies 15% discount on contracts after the first");
  it.todo("rounds the final premium up (in MHPCO's favor)");
});

