const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const PROCESSING_FEE = 5;

export const quote = (_customer: Customer, items: Item[]): QuoteResult => {
  const basePremium = BASE_PREMIUM[items[0].type];
  const withInitialAssessmentTimes100 = basePremium * 110;
  const totalTimes100 = withInitialAssessmentTimes100 + PROCESSING_FEE * 100;
  return { premium: Math.ceil(totalTimes100 / 100) };
};

