const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumBasePremium = (items: Item[]): number => {
  const components: Item[] = [];
  const mainItems: Item[] = [];
  for (const item of items) {
    if (isComponent(item)) components.push(item);
    else mainItems.push(item);
  }

  let total = 0;
  for (const item of mainItems) {
    total += BASE_PREMIUM[item.type];
  }

  const byType = new Map<string, number>();
  for (const c of components) {
    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
  }
  for (const [type, count] of byType) {
    const blocks = Math.floor(count / 3);
    const singles = count % 3;
    total += blocks * COMPONENT_BLOCK_PREMIUM + singles * BASE_PREMIUM[type];
  }

  return total;
};

export const quote = (_customer: Customer, items: Item[]): QuoteResult => {
  const basePremium = sumBasePremium(items);
  const withInitialAssessmentTimes100 = basePremium * 110;
  const totalTimes100 = withInitialAssessmentTimes100 + PROCESSING_FEE * 100;
  return { premium: Math.ceil(totalTimes100 / 100) };
};

